UPDATE TBL_PVE_OPPONENTS
SET BUILD_ID_VS_T = CASE WHEN BUILD_ID_VS_T = #{buildId} THEN NULL ELSE BUILD_ID_VS_T END,
    BUILD_ID_VS_Z = CASE WHEN BUILD_ID_VS_Z = #{buildId} THEN NULL ELSE BUILD_ID_VS_Z END,
    BUILD_ID_VS_P = CASE WHEN BUILD_ID_VS_P = #{buildId} THEN NULL ELSE BUILD_ID_VS_P END
WHERE BUILD_ID_VS_T = #{buildId}
   OR BUILD_ID_VS_Z = #{buildId}
   OR BUILD_ID_VS_P = #{buildId}

